pub struct EventCodec {
    binder: HierBinder,
    paths: [Vec<u8>; 6], // agent,action,patient,time,location,instrument
}

impl EventCodec {
    pub fn new() -> Self {
        // 6 leaves on a depth-3 binary tree (8 slots, use first 6).
        let paths = [
            vec![0,0,0], vec![0,0,1], vec![0,1,0],
            vec![0,1,1], vec![1,0,0], vec![1,0,1],
        ];
        EventCodec { binder: HierBinder::new(6), paths }
    }

    pub fn encode(&self, ev: &[Sparse; 6]) -> Sparse {
        let comps: Vec<_> = self.paths.iter().cloned()
            .zip(ev.iter().cloned()).collect();
        self.binder.bind(&comps)
    }

    /// Unbind role `r` using the (possibly noisy) known others.
    pub fn query_role(&self, t: &Sparse, known: &[(usize, Sparse)], r: usize) -> Sparse {
        let mut acc = t.clone();
        for (i, atom) in known {
            acc = acc.xor(&atom.shift(self.binder.path_shift(&self.paths[*i])));
        }
        self.binder.unbind(&acc, &self.paths[r])
    }
}
